#include "zigbee_zbhci.h"
#include <HardwareSerial.h>
static HardwareSerial zbSerial(2);
void zigbee_setup(){zbSerial.begin(115200,SERIAL_8N1,16,17);Serial.println("[zigbee] OK");}
void zigbee_loop(){}
void zigbee_send(const char*c){zbSerial.println(c);}
String zigbee_receive(){String s="";while(zbSerial.available())s+=(char)zbSerial.read();return s;}
